export function buildCommandActions(language = "en"): CommandAction[] {
  const routeActions = navItems.map((item) => {
    const label = translate(language, `nav.${item.id}`);
    return {
      id: `go-${item.id}`,
      label: translate(language, "command.goTo", { label }),
      description:
        item.id === "tools"
          ? translate(language, "command.openTools")
          : translate(language, "command.openSection", { label: label.toLowerCase() }),
      route: item.id,
      keywords: routeKeywords[item.id] ?? ""
    };
  });
  const settingsActions = settingsCommands.map((command) => ({
    id: `settings-${command.sectionId}`,
    label: command.label,
    description: command.description,
    route: "settings" as RouteId,
    settingsSectionId: command.sectionId
  }));
  return [...routeActions, ...settingsActions];
}

export const commandActions: CommandAction[] = buildCommandActions();

/*
 * Keep this static helper for tests and old call sites. The app uses
 * filterCommandsForLanguage so command labels follow Appearance language.
 */
const legacyCommandActions = navItems.map((item) => ({
  id: `go-${item.id}`,
  label: `Go to ${item.label}`,
  description:
    item.id === "tools"
      ? "Open media tools for platform support matrix, metadata, thumbnails, subtitles, chapters, comments, video clip, shot detection, waveform peaks, and subtitle workshop"
      : `Open the ${item.label.toLowerCase()} section`,
  route: item.id,
  keywords: routeKeywords[item.id] ?? ""
}));

export function filterCommands(query: string): CommandAction[] {
  return filterCommandList(legacyCommandActions, query);
}

export function filterCommandsForLanguage(query: string, language = "en"): CommandAction[] {
  return filterCommandList(buildCommandActions(language), query);
}

function filterCommandList(commands: CommandAction[], query: string): CommandAction[] {
  const normalized = query.trim().toLowerCase();
  if (!normalized) {
    return commands;
  }

  return commands.filter((command) => {
    const setting = command.settingsSectionId
      ? settingsCommands.find((item) => item.sectionId === command.settingsSectionId)
      : null;
    const extraKeywords = setting?.sectionId === "downloads" ? downloadsCleanupCatalogKeywords : "";
    const haystack =
      `${command.label} ${command.description} ${command.keywords ?? ""} ${setting?.keywords ?? ""} ${extraKeywords}`.toLowerCase();
    return haystack.includes(normalized);
  });
}
